mapper.select:
SELECT 
FROM tb_mdm_part t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.code = #{code}


    AND t.name = #{name}


    AND t.name_local = #{nameLocal}


    AND t.part_type = #{partType}


    AND t.is_software = #{isSoftware}


    AND t.status = #{status}


    AND t.is_accurately_traced = #{isAccuratelyTraced}


    AND t.vehicle_node_code = #{vehicleNodeCode}


    AND t.supplier_code = #{supplierCode}


    AND t.fota_upgradeable = #{fotaUpgradeable}


    AND t.source = #{source}


    AND t.external_ref_id = #{externalRefId}


    AND t.external_version = #{externalVersion}


    AND t.last_sync_time = #{lastSyncTime}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC

SELECT 
FROM tb_mdm_part t
WHERE t.row_valid = 1


    AND (t.code LIKE #{key} OR t.name LIKE #{key})


    AND t.code LIKE #{code}


    AND t.name LIKE #{name}


    AND t.part_type = #{partType}


    AND t.vehicle_node_code = #{vehicleNodeCode}

ORDER BY t.id DESC
